function resolveSiteHref(href) {
  const value = String(href || "").trim();
  if (!value || value.startsWith("#") || value.startsWith("mailto:") || value.startsWith("tel:")) {
    return value;
  }
  if (value.startsWith("./") || value.startsWith("../") || value.startsWith("//")) {
    return value;
  }
  if (/^https?:\/\//i.test(value)) {
    return value;
  }
  if (!value.startsWith("/")) {
    return value;
  }

  const url = new URL(value, window.location.origin);
  const normalizedPath = url.pathname.endsWith("/") && url.pathname.length > 1
    ? url.pathname.slice(0, -1)
    : url.pathname;
  const route = staticRouteMap[normalizedPath];
  if (!route) {
    return `${url.pathname}${url.search}${url.hash}`;
  }

  const params = new URLSearchParams(url.search);
  if (route.lang) {
    params.set("lang", route.lang);
  }
  const search = params.toString();
  return `${route.file}${search ? `?${search}` : ""}${url.hash}`;
}

function externalAttrs(href) {
  return href && (href.startsWith("http") || href.startsWith("mailto:") || href.toLowerCase().endsWith(".pptx"))
    ? ' target="_blank" rel="noopener"'
    : "";
}

function link(href, label, className = "") {
  const resolvedHref = resolveSiteHref(href);
  return `<a${className ? ` class="${className}"` : ""} href="${resolvedHref}"${externalAttrs(resolvedHref)}>${label}</a>`;
}

function mobileMainLink(href, label) {
  const resolvedHref = resolveSiteHref(href);
  return `<a class="mobile-panel__primary-link" href="${resolvedHref}"${externalAttrs(resolvedHref)}>${label}</a>`;
}

