function renderFooter() {
  const t = shellCopy();
  return `
    <footer class="footer-band section" id="site-footer">
      <img src="${rootPath}static/picture/logo-wide.png" alt="楚云数航" />
      <p>${t.footerSlogan}</p>
      <div class="footer-line"></div>
      <p class="legal">${t.legal}</p>
    </footer>
  `;
}

function normalizeInternalLinks(scope = document) {
  $$("a[href]", scope).forEach((linkEl) => {
    const href = linkEl.getAttribute("href");
    const resolvedHref = resolveSiteHref(href);
    if (resolvedHref && resolvedHref !== href) {
      linkEl.setAttribute("href", resolvedHref);
    }
  });
}

function renderAboutZhQuickNav() {
  const items = aboutData[pageLanguage].quickNav;
  const quickLabel = pageLanguage === "en" ? "⌖ Quick Nav" : "⌖ 快速导航";
  return `
    <nav class="about-zh-quick-nav" aria-label="${pageLanguage === "en" ? "About page quick navigation" : "关于我们快速导航"}">
      <div class="about-zh-quick-nav__inner">
        <span class="about-zh-quick-nav__label">${quickLabel}</span>
        ${items.map(([labelValue, href]) => `<a href="${href}" data-about-nav-link>${labelValue}</a>`).join("")}
      </div>
    </nav>
  `;
}

function renderAboutZhContactCard(card) {
  const primary = card.email
    ? link(`mailto:${card.email}`, card.email)
    : card.link
      ? link(card.link, card.link)
      : "";
  return `
    <article class="about-zh-contact-card">
      <h3>${card.label}</h3>
      ${primary}
      ${card.phone ? `<p>${card.phone}</p>` : ""}
      ${card.note ? `<small>${card.note}</small>` : ""}
    </article>
  `;
}

function aboutZhOfficeIconKey(city, address) {
  const cityIconMap = {
    "Hong Kong": "香港",
    Shanghai: "上海",
    Beijing: "北京",
    Chengdu: "成都",
    Hangzhou: "杭州",
    Shenzhen: "深圳",
    "South Korea": "韩国",
    Singapore: "新加坡",
    Malaysia: "马来西亚",
    "Abu Dhabi": "阿布扎比",
    Dubai: "迪拜",
    Riyadh: "利雅得"
  };
  if (cityIconMap[city]) return cityIconMap[city];
  if (address.includes("阿布扎比")) return "阿布扎比";
  if (address.includes("迪拜")) return "迪拜";
  if (address.includes("利雅得")) return "利雅得";
  return city;
}

