function aboutZhOfficeTitle(city) {
  return city;
}

function renderSubpageBannerHero({ title, subtitle = "" }) {
  return `
    <section class="subpage-banner-hero">
      <div class="subpage-banner-hero__glow" aria-hidden="true"></div>
      <div class="subpage-banner-hero__content">
        <h1>${title}</h1>
        ${subtitle ? `<p>${subtitle}</p>` : ""}
      </div>
    </section>
  `;
}

function renderAboutZhClonePage() {
  const base = aboutData[pageLanguage];
  const isEnAbout = pageLanguage === "en";
  const { paragraphs, stats, contacts } = base;
  return `
    ${renderSubpageBannerHero({ title: base.title, subtitle: base.subtitle })}
    ${renderAboutZhQuickNav()}
    <section class="about-zh-section about-zh-intro" id="about">
      <h2>${base.aboutTitle}</h2>
      <div class="about-zh-copy">
        ${paragraphs.map((item) => `<p>${item}</p>`).join("")}
      </div>
    </section>
    <section class="about-zh-section about-zh-awards" id="awards">
      <div class="about-zh-stat-grid">
        ${stats
          .map((item) => {
            const [value, maybeSuffix, labelValue] = item;
            const suffix = labelValue ? maybeSuffix : "";
            const label = labelValue || maybeSuffix;
            return `
              <article class="about-zh-stat">
                <strong>${value}${suffix ? `<span>${suffix}</span>` : ""}</strong>
                <p>${label}</p>
              </article>
            `;
          })
          .join("")}
      </div>
    </section>
    <section class="about-zh-section about-zh-contact" id="contact">
      <div class="about-zh-section__center">
        <h2>${base.contactTitle}</h2>
        <p>${base.contactSubtitle || (isEnAbout ? "We look forward to working with you." : "期待与您的合作与交流")}</p>
      </div>
      <div class="about-zh-contact-grid">
        ${contacts.map(renderAboutZhContactCard).join("")}
      </div>
      <div class="about-zh-section__center about-zh-office-head">
        <h3>${base.officesTitle || (isEnAbout ? "Partner Hubs" : "合作与运营据点")}</h3>
        <p>${base.officesSubtitle || (isEnAbout ? "ChuYun Digital Voyage works with partners across multiple cities." : "楚云数航以多城市协同方式服务合作伙伴。")}</p>
      </div>
      <div class="about-zh-office-grid">
        ${base.offices
          .map(([city, country, address]) => {
            const iconKey = aboutZhOfficeIconKey(city, address);
            return `
              <article class="about-zh-office-card">
                <div class="about-zh-office-card__icon" aria-hidden="true">${aboutZhOfficeIconSvg(iconKey)}</div>
                <div>
                  <h4>${aboutZhOfficeTitle(city, country)}</h4>
                  <p>${address}</p>
                </div>
              </article>
            `;
          })
          .join("")}
      </div>
    </section>
  `;
}

function renderAboutPage() {
  return renderAboutZhClonePage();
}

