const investorStockScriptEndpoint = "";
const investorStockScriptVariable = "";
const investorStockFallbackEndpoint = "";

function formatInvestorStockNumber(value, digits = 3) {
  return Number.isFinite(value) ? value.toFixed(digits) : "--";
}

function formatInvestorStockTime(timestampSeconds) {
  if (!Number.isFinite(timestampSeconds)) return "更新时间待确认";
  return new Intl.DateTimeFormat("zh-CN", {
    timeZone: "Asia/Hong_Kong",
    year: "numeric",
    month: "2-digit",
    day: "2-digit",
    hour: "2-digit",
    minute: "2-digit",
    hour12: false
  }).format(new Date(timestampSeconds * 1000));
}

function parseInvestorStockNumber(value) {
  const parsed = Number(String(value || "").replace(/,/g, ""));
  return Number.isFinite(parsed) ? parsed : NaN;
}

function investorStockFirstNumber(fields, indexes) {
  for (const index of indexes) {
    const value = parseInvestorStockNumber(fields[index]);
    if (Number.isFinite(value)) return value;
  }
  return NaN;
}

function parseInvestorStockTimestamp(fields) {
  const slashTime = fields.find((value) => /^\d{4}\/\d{2}\/\d{2} \d{2}:\d{2}(?::\d{2})?$/.test(value || ""));
  if (slashTime) {
    const date = new Date(`${slashTime.replace(/\//g, "-")}+08:00`);
    if (!Number.isNaN(date.getTime())) return date.getTime() / 1000;
  }
  const compactTime = fields.find((value) => /^\d{14}$/.test(value || ""));
  if (compactTime) {
    const year = compactTime.slice(0, 4);
    const month = compactTime.slice(4, 6);
    const day = compactTime.slice(6, 8);
    const hour = compactTime.slice(8, 10);
    const minute = compactTime.slice(10, 12);
    const second = compactTime.slice(12, 14);
    const date = new Date(`${year}-${month}-${day}T${hour}:${minute}:${second}+08:00`);
    if (!Number.isNaN(date.getTime())) return date.getTime() / 1000;
  }
  return Date.now() / 1000;
}

function loadInvestorStockScriptQuote() {
  return new Promise((resolve, reject) => {
    const previousScript = document.querySelector("[data-ir-stock-script]");
    previousScript?.remove();
    window[investorStockScriptVariable] = "";
    const script = document.createElement("script");
    const timeout = window.setTimeout(() => {
      script.remove();
      reject(new Error("Stock script timeout"));
    }, 8000);
    script.dataset.irStockScript = "true";
    script.charset = "gbk";
    script.src = `${investorStockScriptEndpoint}&_=${Date.now()}`;
    script.onload = () => {
      window.clearTimeout(timeout);
      script.remove();
      const raw = window[investorStockScriptVariable];
      const fields = String(raw || "").split("~");
      const price = investorStockFirstNumber(fields, [3, 6, 7]);
      const change = investorStockFirstNumber(fields, [31, 4]);
      const percent = investorStockFirstNumber(fields, [32, 5]);
      if (!Number.isFinite(price)) {
        reject(new Error("Stock script data missing"));
        return;
      }
      resolve({
        price,
        change: Number.isFinite(change) ? change : 0,
        percent: Number.isFinite(percent) ? percent : 0,
        currency: "HKD",
        timestamp: parseInvestorStockTimestamp(fields),
        source: "腾讯证券外部行情接口"
      });
    };
    script.onerror = () => {
      window.clearTimeout(timeout);
      script.remove();
      reject(new Error("Stock script request failed"));
    };
    document.head.appendChild(script);
  });
}

async function fetchInvestorStockFallbackQuote() {
  if (!window.fetch) throw new Error("Fetch API unavailable");
  const response = await fetch(`${investorStockFallbackEndpoint}&_=${Date.now()}`, { cache: "no-store" });
  if (!response.ok) throw new Error(`Stock request failed: ${response.status}`);
  const payload = await response.json();
  const result = payload?.chart?.result?.[0];
  const meta = result?.meta || {};
  const quote = result?.indicators?.quote?.[0] || {};
  const closes = (quote.close || []).filter((value) => Number.isFinite(value));
  const latestClose = closes[closes.length - 1];
  const price = Number(meta.regularMarketPrice ?? latestClose);
  const previousClose = Number(meta.previousClose ?? meta.chartPreviousClose);
  if (!Number.isFinite(price) || !Number.isFinite(previousClose)) throw new Error("Stock data missing");
  const timestamps = result?.timestamp || [];
  const timestamp = Number(meta.regularMarketTime ?? timestamps[timestamps.length - 1]);
  const change = price - previousClose;
  const percent = previousClose ? (change / previousClose) * 100 : 0;
  return {
    price,
    change,
    percent,
    currency: meta.currency || "HKD",
    timestamp,
    source: "Yahoo Finance 外部行情接口"
  };
}

async function fetchInvestorStockQuote() {
  try {
    return await loadInvestorStockScriptQuote();
  } catch (error) {
    return fetchInvestorStockFallbackQuote();
  }
}

function updateInvestorStockCard(quote) {
  const card = $("[data-ir-stock]");
  if (!card) return;
  const priceWrap = $("[data-ir-stock-price-wrap]", card);
  const price = $("[data-ir-stock-price]", card);
  const change = $("[data-ir-stock-change]", card);
  const currency = $("[data-ir-stock-currency]", card);
  const time = $("[data-ir-stock-time]", card);
  const note = $("[data-ir-stock-note]", card);
  const direction = quote.change > 0 ? "up" : quote.change < 0 ? "down" : "flat";
  const prefix = quote.change > 0 ? "+" : "";

  priceWrap?.classList.remove("is-up", "is-down", "is-flat");
  priceWrap?.classList.add(`is-${direction}`);
  if (currency) currency.textContent = quote.currency;
  if (price) price.textContent = formatInvestorStockNumber(quote.price);
  if (change) {
    change.textContent = `${prefix}${formatInvestorStockNumber(quote.change)} (${prefix}${formatInvestorStockNumber(quote.percent, 2)}%)`;
  }
  if (time) time.textContent = formatInvestorStockTime(quote.timestamp);
  if (note) {
    const source = pageLanguage === "en"
      ? quote.source.replace("腾讯证券外部行情接口", "Tencent Finance external quote API").replace("Yahoo Finance 外部行情接口", "Yahoo Finance external quote API")
      : quote.source;
    note.textContent = pageLanguage === "en"
      ? `Source: ${source}. Updates approximately every 60 seconds. Data is for reference only and actual prices are subject to exchange quotes.`
      : `数据来源：${source}，约每 60 秒自动刷新。数据仅供参考，实际价格以交易所实时行情为准。`;
  }
}

